{
  "name": "AmazeBid - Hybrid E-commerce & Auction Platform",
  "description": "A high-end marketplace combining the robust shopping experience of Amazon with the competitive bidding excitement of Yahoo! Auctions, enhanced by Gemini AI.",
  "requestFramePermissions": ["camera", "microphone"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ItemType {
  FIXED_PRICE = 'FIXED_PRICE',
  AUCTION = 'AUCTION'
}

export interface Product {
  id: string;
  title: string;
  description: string;
  price: number;
  currentBid?: number;
  bidCount?: number;
  image: string;
  category: string;
  type: ItemType;
  endTime?: string; // For auctions
  rating: number;
  reviewCount: number;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI } from "@google/genai";
import { Product } from "../types";

export const getShoppingAdvice = async (query: string, products: Product[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const productContext = products.map(p => 
    `- ${p.title} (${p.type === 'AUCTION' ? 'Đấu giá' : 'Mua ngay'}: ${p.price || p.currentBid} USD)`
  ).join('\n');

  const systemInstruction = `
    Bạn là một chuyên gia mua sắm thông minh cho trang web AmazeBid. 
    AmazeBid kết hợp giữa Amazon (mua ngay) và Yahoo Auctions (đấu giá).
    Nhiệm vụ của bạn:
    1. Giúp người dùng chọn sản phẩm phù hợp nhất từ danh sách hiện có.
    2. Giải thích sự khác biệt giữa mua ngay và đấu giá nếu cần.
    3. Trả lời bằng tiếng Việt thân thiện, chuyên nghiệp.

    Danh sách sản phẩm hiện có:
    ${productContext}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: query,
      config: {
        systemInstruction,
        temperature: 0.7,
      },
    });

    return response.text || "Xin lỗi, tôi không thể xử lý yêu cầu này ngay bây giờ.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Có lỗi xảy ra khi kết nối với trí tuệ nhân tạo.";
  }
};

