export default Navbar;

import React, { useState, useEffect } from 'react';
import { Star, Clock, Gavel, ShoppingCart } from 'lucide-react';
import { Product, ItemType } from '../types';

interface ProductCardProps {
  product: Product;
  onAddToCart: (p: Product) => void;
  onPlaceBid: (p: Product) => void;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, onAddToCart, onPlaceBid }) => {
  const [timeLeft, setTimeLeft] = useState<string>('');

  useEffect(() => {
    if (product.type === ItemType.AUCTION && product.endTime) {
      const timer = setInterval(() => {
        const now = new Date().getTime();
        const end = new Date(product.endTime!).getTime();
        const diff = end - now;

        if (diff <= 0) {
          setTimeLeft('Ended');
          clearInterval(timer);
        } else {
          const hours = Math.floor(diff / (1000 * 60 * 60));
          const mins = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
          const secs = Math.floor((diff % (1000 * 60)) / 1000);
          setTimeLeft(`${hours}h ${mins}m ${secs}s`);
        }
      }, 1000);
      return () => clearInterval(timer);
    }
  }, [product]);

  return (
    <div className="bg-white border border-gray-200 rounded p-4 hover:shadow-lg transition-shadow flex flex-col group">
      <div className="relative overflow-hidden aspect-square mb-3">
        <img 
          src={product.image} 
          alt={product.title} 
          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
        />
        {product.type === ItemType.AUCTION && (
          <div className="absolute top-2 left-2 bg-red-600 text-white text-[10px] font-bold px-2 py-0.5 rounded-full flex items-center gap-1 shadow-md">
            <Clock size={10} /> ĐANG ĐẤU GIÁ
          </div>
        )}
      </div>

      <h3 className="text-sm font-medium text-gray-900 line-clamp-2 hover:text-orange-600 cursor-pointer mb-1 h-10">
        {product.title}
      </h3>

      <div className="flex items-center mb-1">
        <div className="flex items-center text-[#febd69]">
          {[...Array(5)].map((_, i) => (
            <Star key={i} size={14} fill={i < Math.floor(product.rating) ? 'currentColor' : 'none'} />
          ))}
        </div>
        <span className="text-xs text-blue-600 ml-1 hover:text-orange-600 cursor-pointer">
          {product.reviewCount.toLocaleString()}
        </span>
      </div>

      <div className="mt-auto">
        {product.type === ItemType.FIXED_PRICE ? (
          <div>
            <div className="flex items-baseline gap-1">
              <span className="text-xs font-bold self-start mt-1">$</span>
              <span className="text-xl font-bold">{Math.floor(product.price)}</span>
              <span className="text-xs font-bold">{(product.price % 1).toFixed(2).substring(2)}</span>
            </div>
            <p className="text-xs text-gray-500 mb-4">Giao hàng miễn phí</p>
            <button 
              onClick={() => onAddToCart(product)}
              className="w-full bg-[#ffd814] hover:bg-[#f7ca00] text-black text-xs py-2 rounded-full font-medium flex items-center justify-center gap-2 shadow-sm"
            >
              <ShoppingCart size={14} /> Thêm vào giỏ
            </button>
          </div>
        ) : (
          <div className="bg-gray-50 p-2 rounded">
            <div className="flex justify-between items-center mb-1">
              <span className="text-[10px] text-gray-500 uppercase font-bold">Giá hiện tại</span>
              <span className="text-xs font-bold text-red-600 flex items-center gap-1">
                <Clock size={12} /> {timeLeft}
              </span>
            </div>
            <div className="flex items-baseline gap-1 mb-1">
              <span className="text-lg font-bold text-red-600">${product.currentBid?.toFixed(2)}</span>
              <span className="text-[10px] text-gray-500">({product.bidCount} lượt trả)</span>
            </div>
            <button 
              onClick={() => onPlaceBid(product)}
              className="w-full bg-[#131921] hover:bg-black text-white text-xs py-2 rounded-full font-medium flex items-center justify-center gap-2"
            >
              <Gavel size={14} /> Trả giá ngay
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default ProductCard;

import React, { useState, useRef, useEffect } from 'react';
import { MessageSquare, X, Send, Sparkles, User, Bot } from 'lucide-react';
import { Message, Product } from '../types';
import { getShoppingAdvice } from '../services/geminiService';

interface GeminiAssistantProps {
  products: Product[];
}

const GeminiAssistant: React.FC<GeminiAssistantProps> = ({ products }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'Chào mừng bạn đến với AmazeBid! Tôi là Gemini Assistant. Bạn cần tìm sản phẩm mua ngay hay muốn tham gia đấu giá?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    const response = await getShoppingAdvice(userMsg, products);

    setMessages(prev => [...prev, { role: 'model', text: response }]);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100]">
      {!isOpen ? (
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-[#131921] text-white p-4 rounded-full shadow-2xl hover:scale-110 transition-transform flex items-center gap-2"
        >
          <Sparkles className="text-[#febd69]" />
          <span className="hidden md:inline font-bold">Hỏi Gemini</span>
        </button>
      ) : (
        <div className="bg-white w-[350px] sm:w-[400px] h-[500px] rounded-2xl shadow-2xl flex flex-col border border-gray-200 overflow-hidden animate-in slide-in-from-bottom-5">
          {/* Header */}
          <div className="bg-[#131921] p-4 text-white flex justify-between items-center">
            <div className="flex items-center gap-2">
              <div className="p-1.5 bg-[#febd69] rounded-lg">
                <Bot size={20} className="text-[#131921]" />
              </div>
              <div>
                <h3 className="font-bold text-sm">Trợ lý Mua sắm AI</h3>
                <p className="text-[10px] text-green-400">Đang trực tuyến (Gemini 3 Flash)</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-gray-700 p-1 rounded">
              <X size={20} />
            </button>
          </div>

          {/* Messages */}
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] rounded-2xl p-3 text-sm shadow-sm ${
                  msg.role === 'user' 
                  ? 'bg-[#131921] text-white rounded-tr-none' 
                  : 'bg-white text-gray-800 border border-gray-200 rounded-tl-none'
                }`}>
                  <p className="whitespace-pre-wrap">{msg.text}</p>
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-gray-200 rounded-2xl p-3 shadow-sm rounded-tl-none flex gap-1">
                  <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                  <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                  <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                </div>
              </div>
            )}
          </div>

          {/* Input */}
          <div className="p-4 border-t border-gray-100 flex gap-2 items-center">
            <input 
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Hỏi về sản phẩm..."
              className="flex-1 bg-gray-100 rounded-full px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-[#febd69]"
            />
            <button 
              onClick={handleSend}
              disabled={isLoading}
              className="bg-[#febd69] p-2 rounded-full hover:bg-orange-500 transition-colors"
            >
              <Send size={18} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default GeminiAssistant;

import React, { useState, useMemo } from 'react';
import Navbar from './components/Navbar';
import ProductCard from './components/ProductCard';
import GeminiAssistant from './components/GeminiAssistant';
import { MOCK_PRODUCTS } from './data';
import { Product, CartItem, ItemType } from './types';
import { ShoppingBag, ChevronRight, X, Minus, Plus, Trash2 } from 'lucide-react';

const App: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [notification, setNotification] = useState<string | null>(null);

  const filteredProducts = useMemo(() => {
    return MOCK_PRODUCTS.filter(p => 
      p.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.category.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [searchTerm]);

  const handleAddToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    showNotification(`Đã thêm ${product.title} vào giỏ hàng`);
  };

  const handlePlaceBid = (product: Product) => {
    showNotification(`Bạn đã đặt giá thầu cho ${product.title}! Theo dõi trong 'Đấu giá của tôi'.`);
  };

  const showNotification = (msg: string) => {
    setNotification(msg);
    setTimeout(() => setNotification(null), 3000);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const totalAmount = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  return (
    <div className="min-h-screen bg-gray-100 pb-20">
      <Navbar 
        cartCount={cart.reduce((s, i) => s + i.quantity, 0)} 
        onSearch={setSearchTerm}
        openCart={() => setIsCartOpen(true)}
      />

      <main className="max-w-[1500px] mx-auto px-4 py-6">
        {/* Banner Section */}
        <div className="relative h-[300px] md:h-[400px] mb-8 overflow-hidden rounded-lg shadow-lg">
          <img 
            src="https://picsum.photos/seed/amazon-banner/1500/600" 
            alt="Promotion Banner"
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-[#131921]/80 to-transparent flex flex-col justify-end p-8 text-white">
            <h1 className="text-4xl font-bold mb-2">Đại Tiệc Mua Sắm & Đấu Giá</h1>
            <p className="text-lg text-[#febd69] font-medium max-w-xl">Hàng ngàn sản phẩm từ điện tử đến đồ cổ hiếm đang chờ bạn sở hữu. Đặt giá ngay hôm nay!</p>
          </div>
        </div>

        {/* Categories Bar */}
        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4 mb-10">
          {['Điện tử', 'Thời trang', 'Đồ cổ', 'Máy tính', 'Nhà cửa', 'Làm đẹp'].map(cat => (
            <div 
              key={cat}
              className="bg-white p-4 rounded shadow-sm hover:shadow-md cursor-pointer text-center group transition-all"
              onClick={() => setSearchTerm(cat)}
            >
              <div className="w-12 h-12 bg-gray-100 rounded-full mx-auto mb-2 flex items-center justify-center group-hover:bg-[#febd69] transition-colors">
                <ShoppingBag size={20} className="text-[#131921]" />
              </div>
              <span className="text-sm font-bold">{cat}</span>
            </div>
          ))}
        </div>

        {/* Dynamic Sections */}
        <div className="space-y-12">
          {/* Featured Auctions */}
          <section>
            <div className="flex items-center justify-between mb-6 border-b-2 border-[#131921] pb-2">
              <div className="flex items-center gap-2">
                <span className="bg-red-600 text-white px-2 py-0.5 rounded text-xs font-bold">HOT</span>
                <h2 className="text-2xl font-bold">Phiên Đấu Giá Nổi Bật</h2>
              </div>
              <button className="text-blue-600 hover:text-orange-600 text-sm font-bold flex items-center">
                Xem tất cả <ChevronRight size={16} />
              </button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
              {filteredProducts.filter(p => p.type === ItemType.AUCTION).map(product => (
                <ProductCard 
                  key={product.id} 
                  product={product} 
                  onAddToCart={handleAddToCart}
                  onPlaceBid={handlePlaceBid}
                />
              ))}
            </div>
          </section>

          {/* Recommended for You */}
          <section>
            <div className="flex items-center justify-between mb-6 border-b-2 border-[#febd69] pb-2">
              <h2 className="text-2xl font-bold">Gợi Ý Mua Sắm</h2>
              <button className="text-blue-600 hover:text-orange-600 text-sm font-bold flex items-center">
                Mua sắm ngay <ChevronRight size={16} />
              </button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
              {filteredProducts.filter(p => p.type === ItemType.FIXED_PRICE).map(product => (
                <ProductCard 
                  key={product.id} 
                  product={product} 
                  onAddToCart={handleAddToCart}
                  onPlaceBid={handlePlaceBid}
                />
              ))}
            </div>
          </section>
        </div>
      </main>

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[100] overflow-hidden">
          <div className="absolute inset-0 bg-black/50" onClick={() => setIsCartOpen(false)} />
          <div className="absolute right-0 top-0 bottom-0 w-full max-w-md bg-white shadow-2xl flex flex-col transform transition-transform duration-300">
            <div className="p-4 bg-[#232f3e] text-white flex justify-between items-center">
              <h2 className="text-xl font-bold flex items-center gap-2">
                <ShoppingBag /> Giỏ hàng của bạn
              </h2>
              <button onClick={() => setIsCartOpen(false)} className="hover:bg-gray-700 p-1 rounded">
                <X size={24} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {cart.length === 0 ? (
                <div className="text-center py-20">
                  <p className="text-gray-500 mb-4">Giỏ hàng của bạn đang trống.</p>
                  <button 
                    onClick={() => setIsCartOpen(false)}
                    className="bg-[#febd69] px-6 py-2 rounded-lg font-bold"
                  >
                    Tiếp tục mua sắm
                  </button>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.id} className="flex gap-4 border-b border-gray-100 pb-4">
                    <img src={item.image} className="w-20 h-20 object-cover rounded" />
                    <div className="flex-1">
                      <h4 className="text-sm font-bold line-clamp-1">{item.title}</h4>
                      <p className="text-lg font-bold text-orange-600">${item.price}</p>
                      <div className="flex items-center gap-4 mt-2">
                        <div className="flex items-center border rounded">
                          <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-gray-100"><Minus size={14}/></button>
                          <span className="px-3 text-sm">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-gray-100"><Plus size={14}/></button>
                        </div>
                        <button onClick={() => removeFromCart(item.id)} className="text-gray-400 hover:text-red-500"><Trash2 size={18}/></button>
                      </div>
