          <section>
            <div className="flex items-center justify-between mb-6 border-b-2 border-[#131921] pb-2">
              <div className="flex items-center gap-2">
                <span className="bg-red-600 text-white px-2 py-0.5 rounded text-xs font-bold">HOT</span>
                <h2 className="text-2xl font-bold">Phiên Đấu Giá Nổi Bật</h2>
              </div>
              <button className="text-blue-600 hover:text-orange-600 text-sm font-bold flex items-center">
                Xem tất cả <ChevronRight size={16} />
              </button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
              {filteredProducts.filter(p => p.type === ItemType.AUCTION).map(product => (
                <ProductCard 
                  key={product.id} 
                  product={product} 
                  onAddToCart={handleAddToCart}
                  onPlaceBid={handlePlaceBid}
                />
              ))}
            </div>
          </section>

          {/* Recommended for You */}
          <section>
            <div className="flex items-center justify-between mb-6 border-b-2 border-[#febd69] pb-2">
