                    </div>
                    {/* ... (Existing checkout logic) ... */}
                    {orderSuccess ? (
                        <div className="flex flex-col items-center justify-center py-6">
                            <CheckCircle2 size={40} className="text-green-600 mb-2" />
                            <p className="font-bold text-green-700">Thành công!</p>
