                                setCameraError(false); // Retry
                            } else {
                                setCameraEnabled(!cameraEnabled);
                            }
                        }} 
                        className={`p-2 rounded hover:bg-white ${!cameraEnabled || cameraError ? 'text-red-600 bg-red-50' : ''}`} 
