import React, { createContext, useState, useContext, useEffect, ReactNode } from 'react';
import { User } from '../types';

interface AuthContextType {
  user: User | null;
  login: (email: string, pass: string) => Promise<boolean>;
  register: (name: string, email: string, pass: string) => Promise<boolean>;
  logout: () => void;
  updateProfile: (updatedData: Partial<User>) => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);

  // Load user from local storage on mount (Simulation)
  useEffect(() => {
    const savedUser = localStorage.getItem('amaze_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const login = async (email: string, pass: string): Promise<boolean> => {
    // Simulate API Call
    return new Promise((resolve) => {
      setTimeout(() => {
        // Mock Login Success
        const mockUser: User = {
          id: 'user_123',
          fullName: 'Nguyễn Văn A',
          email: email,
          avatar: `https://ui-avatars.com/api/?name=Nguyen+Van+A&background=random`,
          joinDate: new Date().toISOString(),
          balance: 0,
          paymentMethods: [
            { id: 'pm_1', type: 'BANK', providerName: 'Vietcombank', accountNumber: '9988776655', holderName: 'NGUYEN VAN A', isDefault: true }
          ]
        };
        setUser(mockUser);
        localStorage.setItem('amaze_user', JSON.stringify(mockUser));
        resolve(true);
      }, 800);
    });
  };

  const register = async (name: string, email: string, pass: string): Promise<boolean> => {
    return new Promise((resolve) => {
      setTimeout(() => {
        const newUser: User = {
          id: `user_${Date.now()}`,
          fullName: name,
          email: email,
          avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(name)}&background=random`,
          joinDate: new Date().toISOString(),
          balance: 0,
          paymentMethods: []
        };
        setUser(newUser);
        localStorage.setItem('amaze_user', JSON.stringify(newUser));
        resolve(true);
      }, 800);
    });
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('amaze_user');
  };

  const updateProfile = (updatedData: Partial<User>) => {
    if (user) {
        const newUser = { ...user, ...updatedData };
        setUser(newUser);
        localStorage.setItem('amaze_user', JSON.stringify(newUser));
    }
  };

  return (
    <AuthContext.Provider value={{ user, login, register, logout, updateProfile }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within an AuthProvider');
  return context;
};

