          <div className="bg-white rounded-2xl p-20 text-center shadow-sm border border-gray-100 animate-in fade-in zoom-in-95">
            <div className="bg-gray-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
              <PackageSearch size={40} className="text-gray-300" />
            </div>
            <h3 className="text-xl font-bold text-gray-800 mb-2">Không tìm thấy sản phẩm</h3>
            <p className="text-gray-500 mb-8 max-w-sm mx-auto">Chúng tôi không tìm thấy kết quả phù hợp với lựa chọn của bạn. Hãy thử thay đổi bộ lọc hoặc từ khóa tìm kiếm.</p>
            <button 
              onClick={() => {
                setSearchTerm('');
                setSelectedCategory('Tất cả');
                setFilterType('ALL');
              }}
              className="text-blue-600 font-bold hover:underline"
            >
              Xóa tất cả bộ lọc
            </button>
          </div>
        )}
      </main>

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[200] overflow-hidden">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity" onClick={() => setIsCartOpen(false)} />
          <div className="absolute right-0 top-0 bottom-0 w-full max-w-md bg-white shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
            <div className="p-5 bg-[#232f3e] text-white flex justify-between items-center shadow-lg">
              <div className="flex items-center gap-3">
                <ShoppingBag size={24} className="text-[#febd69]" />
                <h2 className="text-lg font-bold">Giỏ hàng ({cart.reduce((s, i) => s + i.quantity, 0)})</h2>
              </div>
              <button onClick={() => setIsCartOpen(false)} className="hover:bg-gray-700 p-2 rounded-full transition-colors">
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-5 space-y-6">
              {cart.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-center space-y-4">
                  <div className="bg-gray-100 p-6 rounded-full">
                    <ShoppingBag size={48} className="text-gray-300" />
                  </div>
                  <div>
                    <p className="text-gray-800 font-bold text-lg">Giỏ hàng của bạn đang trống</p>
                    <p className="text-gray-500 text-sm mt-1">Hãy tiếp tục khám phá và thêm sản phẩm!</p>
                  </div>
                  <button 
                    onClick={() => setIsCartOpen(false)} 
                    className="bg-[#febd69] px-8 py-3 rounded-full font-bold shadow-md hover:bg-[#f3a847] transition-all"
                  >
                    Bắt đầu mua sắm
                  </button>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.id} className="flex gap-4 p-3 rounded-xl hover:bg-gray-50 transition-colors border border-transparent hover:border-gray-100 group">
                    <div className="w-24 h-24 shrink-0 rounded-lg overflow-hidden bg-gray-100 border border-gray-200">
                      <img src={item.image} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-1 flex flex-col justify-between">
                      <div>
                        <h4 className="text-sm font-bold text-gray-900 line-clamp-2 leading-tight">{item.title}</h4>
                        <p className="text-xs text-green-600 mt-1">Còn hàng</p>
                      </div>
                      <div className="flex items-center justify-between mt-2">
                        <p className="text-lg font-bold text-[#b12704]">${(item.price * item.quantity).toFixed(2)}</p>
                        <div className="flex items-center gap-3 bg-white border border-gray-300 rounded-lg p-1 shadow-sm">
                          <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-gray-100 rounded text-gray-500"><Minus size={14}/></button>
                          <span className="text-sm font-bold w-4 text-center">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-gray-100 rounded text-gray-500"><Plus size={14}/></button>
                        </div>
                      </div>
                      <button 
                        onClick={() => removeFromCart(item.id)} 
                        className="text-[10px] font-bold text-blue-600 hover:text-red-600 uppercase mt-2 w-fit flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <Trash2 size={12}/> Xóa
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>

            {cart.length > 0 && (
              <div className="p-6 border-t border-gray-100 bg-gray-50 space-y-4">
                <div className="bg-blue-50 p-3 rounded-lg flex gap-2 items-start border border-blue-100">
                    <ShieldCheck className="text-blue-600 shrink-0 mt-0.5" size={16} />
                    <p className="text-[10px] text-blue-800">
                      <strong>Thanh toán an toàn:</strong> Tiền sẽ được AmazeBid giữ lại cho đến khi bạn nhận được hàng và xác nhận hài lòng.
                    </p>
                </div>
                <div className="flex justify-between items-end">
                  <span className="text-gray-500 font-medium">Tổng cộng tạm tính:</span>
                  <div className="text-right">
                    <p className="text-2xl font-bold text-[#b12704]">${totalAmount.toFixed(2)}</p>
                    <p className="text-[10px] text-gray-400 uppercase tracking-widest">Đã bao gồm thuế</p>
                  </div>
                </div>
                <button 
                  onClick={handleCheckout}
                  className="w-full bg-[#ffd814] hover:bg-[#f7ca00] text-black font-bold py-4 rounded-xl shadow-lg transition-all active:scale-[0.98] flex items-center justify-center gap-2"
                >
                  Thanh toán ngay ({cart.length} món)
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Sell Modal */}
      {isSellModalOpen && (
        <SellModal 
          onClose={() => setIsSellModalOpen(false)} 
          onAddProduct={handleAddProduct}
        />
      )}

      {/* Create Stream Modal (New) */}
      {isCreateStreamModalOpen && (
        <CreateStreamModal 
          onClose={() => setIsCreateStreamModalOpen(false)}
          onStartStream={handleCreateStream}
          myProducts={products.filter(p => p.sellerId === user?.id)}
          onOpenSellModal={() => setIsSellModalOpen(true)}
        />
      )}

      {/* Standard Bid Modal */}
      {bidModalProduct && (
        <BidModal 
          product={bidModalProduct}
          onClose={() => setBidModalProduct(null)}
          onSubmitBid={(amount) => handleSubmitBid(bidModalProduct, amount)}
        />
      )}

      {/* Order Dashboard */}
      <OrderDashboard 
        isOpen={isOrderDashboardOpen}
        onClose={() => setIsOrderDashboardOpen(false)}
        products={products}
        currentUserId={user?.id || 'guest'}
        onUpdateStatus={handleOrderStatusUpdate}
      />

      {/* Live Stream Viewer */}
      {activeStream && (
          <LiveStreamViewer 
            stream={activeStream} 
            products={products}
            isHost={isHostMode}
            onClose={() => {
                setActiveStream(null);
                setIsHostMode(false);
            }}
            onPlaceBid={handleSubmitBid}
            onAddToCart={handleAddToCart}
          />
      )}

      {/* Auth Modal */}
      <AuthModal 
        isOpen={isAuthModalOpen} 
        onClose={() => setIsAuthModalOpen(false)} 
      />

      {/* User Profile */}
      <UserProfile 
        isOpen={isProfileOpen} 
        onClose={() => setIsProfileOpen(false)}
        myProducts={myProducts}
        myPosts={contentPosts}
      />

      {/* Customer Service Modal */}
      <CustomerServiceModal 
        isOpen={isCustomerServiceOpen}
        onClose={() => setIsCustomerServiceOpen(false)}
      />

      {/* Content Studio Modal (AI Creative) */}
      <ContentStudioModal
        isOpen={isContentStudioOpen}
        onClose={() => setIsContentStudioOpen(false)}
        onSavePost={handleAddContentPost}
      />

      {/* Notification Toast */}
      {notification && (
        <div className="fixed top-28 left-1/2 -translate-x-1/2 z-[300] bg-[#131921] text-white px-8 py-3 rounded-2xl shadow-2xl animate-in fade-in slide-in-from-top-4 border-2 border-[#febd69] flex items-center gap-3">
          <div className="bg-[#febd69] p-1 rounded-full">
            <Sparkles className="text-black" size={16} />
          </div>
          <span className="text-sm font-bold tracking-tight">{notification}</span>
        </div>
      )}

      <GeminiAssistant products={products} />
    </div>
  );
};

const App: React.FC = () => {
    return (
        <AuthProvider>
            <InnerApp />
        </AuthProvider>
    )
}

export default App;

import React, { useState, useRef } from 'react';
import { X, PenTool, Image as ImageIcon, Video, Share2, Sparkles, LayoutTemplate, Save, Download, ChevronRight, Wand2, Globe, CheckCircle2, Copy } from 'lucide-react';
import { generateSEOContent, generateProductImage, generateProductVideo } from '../services/geminiService';
import { ContentPost } from '../types';

interface ContentStudioModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSavePost?: (post: ContentPost) => void;
}

const ContentStudioModal: React.FC<ContentStudioModalProps> = ({ isOpen, onClose, onSavePost }) => {
  // Steps: 1=Info, 2=Text, 3=Visuals, 4=Review
  const [step, setStep] = useState(1);
  const [isLoading, setIsLoading] = useState(false);

  // Data State
  const [productName, setProductName] = useState('');
  const [keywords, setKeywords] = useState('');
  const [tone, setTone] = useState('Chuyên nghiệp & Tin cậy');

  const [generatedContent, setGeneratedContent] = useState('');
  const [generatedImages, setGeneratedImages] = useState<string[]>([]);
  const [generatedVideo, setGeneratedVideo] = useState<string | null>(null);

  // Generation Prompts
  const [imagePrompt, setImagePrompt] = useState('');
  const [videoPrompt, setVideoPrompt] = useState('');

  if (!isOpen) return null;

  // --- Handlers ---

  const handleGenerateText = async () => {
    if (!productName) return;
    setIsLoading(true);
    try {
        const text = await generateSEOContent(productName, keywords, tone);
        setGeneratedContent(text);

        // Auto-suggest prompts based on product name
        setImagePrompt(`Professional product photography of ${productName}, studio lighting, 4k resolution, cinematic.`);
        setVideoPrompt(`Cinematic commercial shot of ${productName}, slow motion, elegant lighting.`);

        setStep(2);
    } catch (e) {
        alert("Lỗi tạo nội dung. Vui lòng thử lại.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleGenerateImage = async () => {
      setIsLoading(true);
      try {
          const imgData = await generateProductImage(imagePrompt);
          if (imgData) {
              setGeneratedImages(prev => [...prev, imgData]);
          }
      } catch (e) {
          alert("Lỗi tạo ảnh. (Lưu ý: Tính năng này cần API Key có quyền Imagen)");
      } finally {
          setIsLoading(false);
      }
  };

  const handleGenerateVideo = async () => {
      setIsLoading(true);
      try {
          const videoUrl = await generateProductVideo(videoPrompt);
          if (videoUrl) {
              setGeneratedVideo(videoUrl);
          }
      } catch (e) {
          alert("Lỗi tạo video. (Lưu ý: Tính năng này cần API Key có quyền Veo và cần người dùng tự chọn key trong môi trường thực tế)");
      } finally {
          setIsLoading(false);
      }
  };

  const handlePublish = () => {
      if (onSavePost) {
          const newPost: ContentPost = {
              id: `post_${Date.now()}`,
              title: productName,
              content: generatedContent,
              keywords: keywords.split(',').map(k => k.trim()),
              generatedImages: generatedImages,
              generatedVideo: generatedVideo || undefined,
              status: 'PUBLISHED',
              platform: 'BLOG',
              createdAt: new Date().toISOString()
          };
          onSavePost(newPost);
      }
      onClose();
  };

  // --- Render Steps ---

  const renderStep1_Info = () => (
      <div className="space-y-6 animate-in slide-in-from-right">
          <div className="bg-blue-50 p-4 rounded-xl border border-blue-100 flex gap-3">
              <Sparkles className="text-blue-600 shrink-0" />
              <div>
                  <h3 className="font-bold text-blue-800">Bắt đầu ý tưởng</h3>
                  <p className="text-sm text-blue-700">AI sẽ tự động thu thập thông tin sản phẩm từ Google Search để viết bài chuẩn SEO.</p>
              </div>
          </div>

          <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Tên sản phẩm / Chủ đề</label>
              <input 
                value={productName}
                onChange={e => setProductName(e.target.value)}
                placeholder="VD: iPhone 15 Pro Max, Nồi chiên không dầu Philips..."
                className="w-full p-3 border-2 border-gray-200 rounded-xl focus:border-[#febd69] outline-none font-medium"
              />
          </div>

          <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Từ khóa SEO (ngăn cách bởi dấu phẩy)</label>
              <input 
                value={keywords}
                onChange={e => setKeywords(e.target.value)}
                placeholder="VD: giá rẻ, chính hãng, review chi tiết, khuyến mãi..."
                className="w-full p-3 border border-gray-200 rounded-xl focus:border-[#febd69] outline-none"
              />
          </div>

          <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Giọng văn (Tone of Voice)</label>
              <select 
                value={tone}
                onChange={e => setTone(e.target.value)}
                className="w-full p-3 border border-gray-200 rounded-xl bg-white outline-none"
              >
                  <option>Chuyên nghiệp & Tin cậy</option>
                  <option>Hài hước & Thân thiện</option>
                  <option>Sang trọng & Đẳng cấp</option>
                  <option>Ngắn gọn & Súc tích</option>
              </select>
          </div>

          <button 
            onClick={handleGenerateText}
            disabled={!productName || isLoading}
            className="w-full bg-[#131921] text-white py-4 rounded-xl font-bold hover:bg-black transition-all flex items-center justify-center gap-2 disabled:opacity-50"
          >
              {isLoading ? <Wand2 className="animate-spin"/> : <PenTool size={20}/>}
              {isLoading ? 'AI Đang Viết...' : 'Tạo Bài Viết Ngay'}
          </button>
      </div>
  );

  const renderStep2_Text = () => (
      <div className="flex flex-col h-full animate-in slide-in-from-right">
          <div className="flex justify-between items-center mb-4">
              <h3 className="font-bold text-lg">Nội dung SEO (Bản nháp)</h3>
              <button onClick={() => setStep(3)} className="bg-[#febd69] px-4 py-2 rounded-lg font-bold text-sm">Tiếp theo: Hình ảnh</button>
          </div>
          <textarea 
            value={generatedContent}
            onChange={e => setGeneratedContent(e.target.value)}
            className="flex-1 w-full p-6 bg-gray-50 border border-gray-200 rounded-xl resize-none outline-none focus:bg-white transition-colors font-serif text-lg leading-relaxed shadow-inner"
          />
          <div className="mt-4 flex gap-2 overflow-x-auto pb-2">
               <span className="text-xs font-bold text-gray-400 uppercase">Gợi ý chỉnh sửa:</span>
               {['Thêm Emoji', 'Viết dài hơn', 'Tóm tắt lại', 'Thêm thông số kỹ thuật'].map(act => (
                   <button key={act} className="px-3 py-1 bg-gray-100 rounded-full text-xs font-medium hover:bg-gray-200 whitespace-nowrap">
                       {act}
                   </button>
               ))}
          </div>
      </div>
  );

  const renderStep3_Visuals = () => (
      <div className="h-full overflow-y-auto custom-scrollbar space-y-8 animate-in slide-in-from-right pr-2">
          {/* Image Section */}
          <div>
              <h3 className="font-bold text-lg flex items-center gap-2 mb-4">
                  <ImageIcon className="text-blue-600"/> Studio Hình ảnh (Imagen 3)
              </h3>
              <div className="flex gap-2 mb-4">
                  <input 
                    value={imagePrompt}
                    onChange={e => setImagePrompt(e.target.value)}
                    className="flex-1 border border-gray-300 rounded-lg px-3 py-2 text-sm"
                    placeholder="Mô tả hình ảnh bạn muốn tạo..."
                  />
                  <button 
                    onClick={handleGenerateImage}
                    disabled={isLoading}
                    className="bg-blue-600 text-white px-4 rounded-lg font-bold text-sm hover:bg-blue-700 disabled:opacity-50"
                  >
                      {isLoading ? '...' : 'Tạo Ảnh'}
                  </button>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                  {generatedImages.map((img, i) => (
                      <div key={i} className="relative aspect-square rounded-xl overflow-hidden border border-gray-200 group">
                          <img src={img} className="w-full h-full object-cover" />
                          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                              <button className="p-2 bg-white rounded-full hover:bg-gray-100"><Download size={16}/></button>
                          </div>
                      </div>
                  ))}
                  {generatedImages.length === 0 && (
                      <div className="col-span-full h-32 bg-gray-50 rounded-xl border border-dashed border-gray-300 flex items-center justify-center text-gray-400 text-sm">
                          Chưa có hình ảnh nào được tạo.
                      </div>
                  )}
              </div>
          </div>

          <div className="border-t border-gray-200 my-4"/>

          {/* Video Section */}
          <div>
              <h3 className="font-bold text-lg flex items-center gap-2 mb-4">
                  <Video className="text-red-600"/> Studio Video (Veo)
              </h3>
              <div className="bg-orange-50 p-3 rounded-lg text-xs text-orange-800 mb-4 flex items-center gap-2">
                  <Wand2 size={14}/> Video được tạo bởi mô hình Veo mới nhất. Quá trình có thể mất 1-2 phút.
              </div>
              <div className="flex gap-2 mb-4">
                  <input 
                    value={videoPrompt}
                    onChange={e => setVideoPrompt(e.target.value)}
                    className="flex-1 border border-gray-300 rounded-lg px-3 py-2 text-sm"
                    placeholder="Mô tả video quảng cáo..."
                  />
                  <button 
                     onClick={handleGenerateVideo}
                     disabled={isLoading}
                     className="bg-red-600 text-white px-4 rounded-lg font-bold text-sm hover:bg-red-700 disabled:opacity-50"
                  >
                      {isLoading ? 'Đang render...' : 'Tạo Video'}
                  </button>
              </div>

              {generatedVideo ? (
                  <div className="rounded-xl overflow-hidden bg-black aspect-video relative shadow-lg">
                      <video src={generatedVideo} controls className="w-full h-full" />
                  </div>
              ) : (
                  <div className="h-48 bg-gray-50 rounded-xl border border-dashed border-gray-300 flex items-center justify-center text-gray-400 text-sm flex-col gap-2">
                      <Video size={32} className="opacity-20"/>
                      <span>Khu vực hiển thị Video Preview</span>
                  </div>
              )}
          </div>

          <div className="pt-4 flex justify-end">
              <button onClick={() => setStep(4)} className="bg-[#131921] text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2">
                  Xem bản hoàn chỉnh <ChevronRight size={18}/>
              </button>
          </div>
      </div>
  );

  const renderStep4_Review = () => (
      <div className="h-full flex flex-col animate-in slide-in-from-right">
          <div className="flex-1 overflow-y-auto custom-scrollbar bg-gray-50 p-6 rounded-xl border border-gray-200 mb-4">
              {/* Blog Post Preview UI */}
              <article className="max-w-2xl mx-auto bg-white p-8 rounded-lg shadow-sm">
                  <h1 className="text-3xl font-black text-gray-900 mb-4 leading-tight">{productName}</h1>
                  <div className="flex items-center gap-2 text-xs text-gray-500 mb-6">
                      <img src="https://ui-avatars.com/api/?name=Admin&background=random" className="w-6 h-6 rounded-full"/>
                      <span>Bởi <strong>Content AI</strong></span>
                      <span>•</span>
                      <span>{new Date().toLocaleDateString()}</span>
                  </div>

                  {generatedVideo && (
                      <div className="mb-8 rounded-xl overflow-hidden shadow-lg">
                          <video src={generatedVideo} controls className="w-full" />
                      </div>
                  )}

                  {generatedImages.length > 0 && (
                      <img src={generatedImages[0]} className="w-full h-auto rounded-xl mb-8 object-cover shadow-md" alt="Main visual"/>
                  )}

                  <div className="prose prose-lg text-gray-700 whitespace-pre-wrap font-serif">
                      {generatedContent}
                  </div>

                  {generatedImages.length > 1 && (
                      <div className="grid grid-cols-2 gap-4 mt-8">
                          {generatedImages.slice(1).map((img, i) => (
                              <img key={i} src={img} className="rounded-lg shadow-sm w-full h-32 object-cover"/>
                          ))}
                      </div>
                  )}
              </article>
          </div>

          <div className="flex justify-between items-center border-t border-gray-100 pt-4">
               <button onClick={() => setStep(3)} className="text-gray-500 font-bold hover:text-black">Quay lại</button>
               <div className="flex gap-3">
                   <button className="flex items-center gap-2 px-4 py-3 bg-white border border-gray-300 rounded-xl font-bold hover:bg-gray-50">
                       <Save size={18}/> Lưu nháp
                   </button>
                   <button 
                    onClick={handlePublish}
                    className="flex items-center gap-2 px-6 py-3 bg-[#febd69] text-black rounded-xl font-bold hover:bg-[#f3a847] shadow-lg"
                   >
                       <Share2 size={18}/> Đăng & Chia sẻ
                   </button>
               </div>
          </div>
      </div>
  );

  return (
    <div className="fixed inset-0 z-[250] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm animate-in fade-in" onClick={onClose} />
      <div className="relative bg-white w-full max-w-6xl h-[90vh] rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in zoom-in-95">

        {/* Sidebar Nav */}
        <div className="w-full md:w-64 bg-[#131921] text-white p-6 flex flex-col shrink-0">
            <h2 className="text-2xl font-bold italic mb-8 flex items-center gap-2">
                <Wand2 className="text-[#febd69]"/> Content<span className="text-[#febd69]">Studio</span>
            </h2>

            <div className="space-y-2 relative">
                {/* Step Indicators */}
                {[
                    { id: 1, label: 'Thông tin & Ý tưởng', icon: LayoutTemplate },
                    { id: 2, label: 'AI Writer', icon: PenTool },
                    { id: 3, label: 'Media (Ảnh/Video)', icon: ImageIcon },
                    { id: 4, label: 'Review & Đăng', icon: Share2 },
                ].map((s, idx) => (
                    <div 
                        key={s.id}
                        className={`flex items-center gap-3 p-3 rounded-lg transition-all ${step === s.id ? 'bg-[#febd69] text-black font-bold' : 'text-gray-400'}`}
                    >
                        <div className={`w-6 h-6 rounded-full flex items-center justify-center text-xs border ${step === s.id ? 'border-black' : 'border-gray-500'}`}>
                            {step > s.id ? <CheckCircle2 size={14}/> : s.id}
                        </div>
                        <span className="text-sm">{s.label}</span>
                    </div>
                ))}

                {/* Connecting Line (Visual only) */}
                <div className="absolute left-[23px] top-8 bottom-8 w-px bg-gray-700 -z-10"></div>
            </div>

            <div className="mt-auto bg-gray-800 p-4 rounded-xl text-xs text-gray-400">
                <p className="font-bold text-white mb-1">AI Power</p>
                <div className="flex flex-col gap-1">
                    <span className="flex items-center gap-1"><CheckCircle2 size={10} className="text-green-500"/> Gemini 3 Pro (Text)</span>
                    <span className="flex items-center gap-1"><CheckCircle2 size={10} className="text-green-500"/> Imagen 3 (Image)</span>
                    <span className="flex items-center gap-1"><CheckCircle2 size={10} className="text-green-500"/> Veo (Video)</span>
                </div>
            </div>
        </div>

        {/* Main Workspace */}
        <div className="flex-1 flex flex-col relative h-full">
            <div className="absolute top-4 right-4 z-10">
                <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full bg-white shadow-sm border border-gray-100">
                    <X size={20} className="text-gray-500"/>
                </button>
            </div>

            <div className="flex-1 p-8 overflow-hidden h-full">
                {step === 1 && renderStep1_Info()}
                {step === 2 && renderStep2_Text()}
                {step === 3 && renderStep3_Visuals()}
                {step === 4 && renderStep4_Review()}
            </div>
        </div>
      </div>
    </div>
  );
};

export default ContentStudioModal;

import React, { useState, useEffect } from 'react';
import { User, CreditCard, ShieldCheck, MapPin, Eye, EyeOff, Edit2, Plus, LogOut, Lock, X, Share2, Copy, Check, Facebook, Instagram, Chrome, Users, Link, Save, Trash2, AlertTriangle, Phone, FileText, ShoppingBag, Gavel, Calendar } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { PaymentMethod, SocialAccount, Product, ContentPost, ItemType } from '../types';

interface UserProfileProps {
  isOpen: boolean;
  onClose: () => void;
  myProducts?: Product[];
  myPosts?: ContentPost[];
}

const UserProfile: React.FC<UserProfileProps> = ({ isOpen, onClose, myProducts = [], myPosts = [] }) => {
  const { user, logout, updateProfile } = useAuth();
  const [activeTab, setActiveTab] = useState<'INFO' | 'PAYMENT' | 'SECURITY' | 'SOCIAL' | 'POSTS'>('INFO');
  const [showSensitive, setShowSensitive] = useState<Record<string, boolean>>({});
  const [copied, setCopied] = useState(false);
  const [friendCodeInput, setFriendCodeInput] = useState('');

  // --- CRUD States ---
  // 1. Profile Edit State
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [profileForm, setProfileForm] = useState({ fullName: '', phone: '', address: '' });

  // 2. Payment CRUD State
  const [isAddingCard, setIsAddingCard] = useState(false);
  const [cardForm, setCardForm] = useState({ provider: 'Visa', number: '', holder: '' });

  // Init form data when user loads
  useEffect(() => {
    if (user) {
        setProfileForm({
            fullName: user.fullName || '',
            phone: user.phone || '',
            address: user.address || ''
        });
    }
  }, [user, isOpen]);

  if (!isOpen || !user) return null;

  const toggleVisibility = (id: string) => {
    setShowSensitive(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const maskedNumber = (num: string) => {
    if (!num) return '****';
    return `**** **** **** ${num.slice(-4)}`;
  };

  // --- Profile CRUD Functions ---
  const handleSaveProfile = () => {
      updateProfile({
          fullName: profileForm.fullName,
          phone: profileForm.phone,
          address: profileForm.address
      });
      setIsEditingProfile(false);
  };

  const handleCancelEdit = () => {
      setProfileForm({
          fullName: user.fullName,
          phone: user.phone || '',
          address: user.address || ''
      });
      setIsEditingProfile(false);
  };

  // --- Payment CRUD Functions ---
  const handleSaveNewCard = (e: React.FormEvent) => {
    e.preventDefault();
    if (cardForm.number.length < 4 || !cardForm.holder) return;

    const newPayment: PaymentMethod = {
        id: `pm_${Date.now()}`,
        type: 'CARD',
        providerName: cardForm.provider,
        accountNumber: cardForm.number,
        holderName: cardForm.holder.toUpperCase(),
        isDefault: user.paymentMethods.length === 0
    };

    updateProfile({
        paymentMethods: [...user.paymentMethods, newPayment]
    });

    // Reset & Close
    setCardForm({ provider: 'Visa', number: '', holder: '' });
    setIsAddingCard(false);
  };

  const handleDeletePayment = (id: string) => {
      if (confirm('Bạn có chắc chắn muốn xóa phương thức thanh toán này?')) {
          const updatedMethods = user.paymentMethods.filter(pm => pm.id !== id);
          updateProfile({ paymentMethods: updatedMethods });
      }
  };

  // --- Social Logic ---
  const toggleSocialConnection = (provider: string) => {
      const currentAccounts = user.socialAccounts || [];
      const exists = currentAccounts.find(a => a.provider === provider);

      let newAccounts: SocialAccount[];

      if (exists) {
          newAccounts = currentAccounts.map(a => 
              a.provider === provider ? { ...a, connected: !a.connected } : a
          );
      } else {
          newAccounts = [...currentAccounts, { provider: provider as any, connected: true, username: 'user_connected' }];
      }

      updateProfile({ socialAccounts: newAccounts });
  };

  const handleCopyCode = () => {
      if (user.referralCode) {
          navigator.clipboard.writeText(user.referralCode);
          setCopied(true);
          setTimeout(() => setCopied(false), 2000);
      }
  };

  const handleDeleteAccount = () => {
      const confirmation = prompt('Hành động này không thể hoàn tác. Nhập "DELETE" để xác nhận xóa tài khoản:');
      if (confirmation === 'DELETE') {
          alert('Tài khoản đã được xóa. Tạm biệt!');
          logout();
          onClose();
      }
  };

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={onClose} />
      <div className="relative bg-white w-full max-w-4xl h-[80vh] rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in zoom-in-95">

        {/* Sidebar */}
        <div className="w-full md:w-64 bg-gray-50 border-r border-gray-200 p-6 flex flex-col">
            <div className="text-center mb-6">
                <div className="w-20 h-20 mx-auto rounded-full overflow-hidden border-2 border-[#febd69] mb-3 group relative">
                    <img src={user.avatar} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/30 opacity-0 group-hover:opacity-100 flex items-center justify-center cursor-pointer transition-opacity">
                        <Edit2 className="text-white" size={20}/>
                    </div>
                </div>
                <h3 className="font-bold text-lg">{user.fullName}</h3>
                <p className="text-xs text-gray-500">{user.email}</p>
                <div className="mt-2 inline-flex items-center gap-1 px-2 py-0.5 bg-green-100 text-green-700 rounded text-[10px] font-bold">
                    <ShieldCheck size={10} /> Verified
                </div>
            </div>

            <nav className="space-y-2 flex-1">
                <button 
                    onClick={() => setActiveTab('INFO')}
                    className={`w-full text-left px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-3 ${activeTab === 'INFO' ? 'bg-[#131921] text-white' : 'hover:bg-gray-200 text-gray-600'}`}
                >
                    <User size={16} /> Thông tin cá nhân
                </button>
                <button 
                    onClick={() => setActiveTab('POSTS')}
