  const handleEmailSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    try {
        if (view === 'LOGIN') {
            await login(formData.email, formData.password);
        } else {
            await register(formData.name, formData.email, formData.password);
        }
        onClose();
    } catch (error) {
        console.error("Auth error", error);
    } finally {
        setIsLoading(false);
    }
  };

