export enum ItemType {
  FIXED_PRICE = 'FIXED_PRICE',
  AUCTION = 'AUCTION'
}

export enum OrderStatus {
  AVAILABLE = 'AVAILABLE',
  PENDING_SHIPMENT = 'PENDING_SHIPMENT',
  SHIPPED = 'SHIPPED',
  DELIVERED = 'DELIVERED',
  COMPLETED = 'COMPLETED',
  RETURNED = 'RETURNED'
}

export interface Bid {
  id: string;
  userId: string;
  userName: string;
  amount: number;
  timestamp: string;
}

export interface PaymentMethod {
  id: string;
  type: 'BANK' | 'CARD' | 'WALLET';
  providerName: string; // Vietcombank, Visa, Momo
  accountNumber: string; // Will be masked in UI
  holderName: string;
  isDefault: boolean;
}

export interface SocialAccount {
  provider: 'facebook' | 'google' | 'instagram' | 'twitter';
  connected: boolean;
  username?: string;
}

export interface User {
  id: string;
  fullName: string;
  email: string;
  phone?: string;
  avatar: string;
  address?: string;
  joinDate: string;
  balance: number; // For wallet
  paymentMethods: PaymentMethod[];
  // Social & Referral
  socialAccounts?: SocialAccount[];
  referralCode?: string;
  referredBy?: string;
  friendCount?: number;
  role?: 'USER' | 'ADMIN'; // Added Role
}

// New Interface for Admin Reporting
export interface Transaction {
