// --- Virtual Avatar Types ---

export interface AvatarCustomization {
  heightScale: number; // 0.9 to 1.1
  skinToneHash: string; // Hex color for overlay tint
  hairStyle: 'LONG' | 'SHORT' | 'BOB' | 'PONYTAIL';
