  currentBid?: number;
  bidCount?: number;
  bidHistory?: Bid[]; // New: List of bids
  stepPrice?: number; // New: Minimum increment
  image: string;
  category: string;
  type: ItemType;
  endTime?: string; 
  rating: number;
  reviewCount: number;
  status: OrderStatus;
  sellerId: string;
