import React, { useState, useEffect, useRef, useMemo, Suspense } from 'react';
import { X, User, Shirt, Image as ImageIcon, Video, Mic, Music, Sparkles, MessageSquare, Monitor, Zap, Bot, Radio, Sliders, Palette, Languages, Speaker, Scissors, Box, Move3d } from 'lucide-react';
import { MOCK_AVATARS, MOCK_OUTFITS, MOCK_ENVIRONMENTS } from '../data';
import { GoogleGenAI } from "@google/genai";
import { Product, AvatarCustomization } from '../types';

// --- 3D IMPORTS ---
import { Canvas, useFrame } from '@react-three/fiber';
import { useGLTF, OrbitControls, Environment, ContactShadows, Float } from '@react-three/drei';
import * as THREE from 'three';

interface VirtualAvatarStudioProps {
  isOpen: boolean;
  onClose: () => void;
  products: Product[];
}

type AvatarState = 'IDLE' | 'TALKING' | 'SINGING';

// --- 3D COMPONENT: STATIC MODEL HANDLER ---
// Đây là component xử lý mô hình tĩnh. Nó nhận các tham số (props) và trực tiếp can thiệp vào Mesh
const Avatar3DModel = ({ url, customization, isTalking }: { url: string, customization: AvatarCustomization, isTalking: boolean }) => {
  // Tải mô hình từ URL (GLB/GLTF)
  const { scene } = useGLTF(url);

  // Clone scene để không ảnh hưởng đến cache gốc (quan trọng khi đổi màu)
  const clone = useMemo(() => scene.clone(), [scene]);
  const groupRef = useRef<THREE.Group>(null);

  // Tạo hiệu ứng "thở" hoặc rung nhẹ khi nói bằng code (vì không có bone animation)
  useFrame((state) => {
      if (groupRef.current) {
          const t = state.clock.getElapsedTime();

          // Hiệu ứng thở (Scale nhẹ lồng ngực/toàn thân)
          const breathingScale = 1 + Math.sin(t * 2) * 0.005;

          // Hiệu ứng nói (Rung nhẹ nếu đang nói)
          const talkingShake = isTalking ? Math.sin(t * 20) * 0.002 : 0;

          groupRef.current.scale.set(
              customization.heightScale * breathingScale, 
              customization.heightScale * (breathingScale + talkingShake), 
              customization.heightScale * breathingScale
          );

          // Xoay nhẹ tự nhiên (Idle sway)
          groupRef.current.rotation.y = Math.sin(t * 0.5) * 0.05;
      }
  });

  // Áp dụng màu da (Skin Tone) trực tiếp lên các Mesh
  useEffect(() => {
      clone.traverse((child: any) => {
          if (child.isMesh) {
              // Logic đơn giản: Nếu tên mesh chứa "Skin" hoặc "Body", đổi màu
              // Thực tế bạn cần biết tên chính xác của mesh trong file 3D
              if (child.name.includes('Body') || child.name.includes('Skin') || child.name.includes('Head')) {
                  // Đổi màu vật liệu
                  child.material = child.material.clone();
                  child.material.color.set(customization.skinToneHash);
              }
              // Bật bóng đổ
              child.castShadow = true;
              child.receiveShadow = true;
          }
      });
  }, [clone, customization.skinToneHash]);

  return (
      <group ref={groupRef} position={[0, -1.5, 0]}>
          <primitive object={clone} />
      </group>
  );
};

const VirtualAvatarStudio: React.FC<VirtualAvatarStudioProps> = ({ isOpen, onClose, products }) => {
  const [activeTab, setActiveTab] = useState<'SETUP' | 'CUSTOMIZE' | 'STUDIO' | 'LIVE'>('SETUP');

  // Avatar Configuration State
  const [selectedAvatar, setSelectedAvatar] = useState(MOCK_AVATARS[0]);
  const [selectedOutfit, setSelectedOutfit] = useState(MOCK_OUTFITS[0]);
  const [selectedEnv, setSelectedEnv] = useState(MOCK_ENVIRONMENTS[0]);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(products[0] || null);

  // Toggle between Video Mode (2D) and Real-time 3D Mode
  const [use3DMode, setUse3DMode] = useState(false);

  // New: Advanced Customization State
  const [customization, setCustomization] = useState<AvatarCustomization>({
      heightScale: 1.0,
      skinToneHash: '#ffffff', // Default neutral
      hairStyle: 'LONG',
      language: 'vi-VN',
      voiceSpeed: 1.1,
      voicePitch: 1.0
  });

  // Live State
  const [isLive, setIsLive] = useState(false);
  const [avatarState, setAvatarState] = useState<AvatarState>('IDLE');
  const [chatHistory, setChatHistory] = useState<{user: string, text: string}[]>([]);
  const [lyrics, setLyrics] = useState<string[]>([]);

  // Audio Visualizer Mock
  const [audioLevel, setAudioLevel] = useState<number[]>(new Array(10).fill(10));

  const videoRef = useRef<HTMLVideoElement>(null);

  // Effect to handle video source switching based on state
  useEffect(() => {
      if (videoRef.current && !use3DMode) {
          let nextSrc = selectedAvatar.idleVideo;
          if (avatarState === 'TALKING') nextSrc = selectedAvatar.talkingVideo;
          if (avatarState === 'SINGING') nextSrc = selectedAvatar.singingVideo || selectedAvatar.talkingVideo;

          if (!videoRef.current.src.includes(nextSrc)) {
