                              <OrbitControls enablePan={false} enableZoom={true} minPolarAngle={Math.PI / 2.5} maxPolarAngle={Math.PI / 2} />
                          </Canvas>

                          {/* 3D Mode Badge */}
                          <div className="absolute bottom-4 left-4 bg-blue-600/80 backdrop-blur px-3 py-1 rounded text-xs font-bold text-white flex items-center gap-1">
