                  {/* Effects Layer (Singing, Speaking) - Shared between 2D/3D */}
                  {avatarState === 'SINGING' && (
                      <div className="absolute top-1/3 inset-x-0 text-center space-y-2 animate-bounce-slow pointer-events-none">
