import React, { Component, ReactNode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

interface ErrorBoundaryProps {
  children: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: any;
}

// Error Boundary Component
class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: any): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: any, errorInfo: any) {
    console.error("App Crash:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{
          padding: '2rem',
          fontFamily: 'sans-serif',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          height: '100vh',
          backgroundColor: '#f8d7da',
          color: '#721c24',
          textAlign: 'center'
        }}>
          <h1 style={{fontSize: '2rem', marginBottom: '1rem'}}>Đã có lỗi xảy ra!</h1>
          <p style={{marginBottom: '1rem'}}>Ứng dụng không thể tải. Vui lòng thử tải lại trang.</p>
          <pre style={{
             backgroundColor: 'white',
             padding: '1rem',
             borderRadius: '8px',
             maxWidth: '800px',
             overflow: 'auto',
             border: '1px solid #f5c6cb',
             textAlign: 'left',
             fontSize: '0.8rem'
          }}>
            {this.state.error?.message || 'Unknown Error'}
          </pre>
          <button 
            onClick={() => window.location.reload()}
            style={{
                marginTop: '2rem',
                padding: '10px 20px',
                fontSize: '1rem',
                backgroundColor: '#131921',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer'
            }}
          >
            Tải lại trang
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

const container = document.getElementById('root');

if (container) {
  try {
      const root = createRoot(container);
      root.render(
        <React.StrictMode>
          <ErrorBoundary>
            <App />
          </ErrorBoundary>
        </React.StrictMode>
      );
  } catch (e) {
      console.error("Mounting Error:", e);
      container.innerHTML = '<div style="color:red; padding:20px;">Critical Error: Failed to mount application. Check console.</div>';
  }
} else {
  console.error("Failed to find the root element");
}

